export const faqCategories: FaqCategory[] = rawFaqCategories.map((category) => ({
  ...category,
  items: category.items.map((item) => ({
    ...item,
    a: compactAnswer(item.a),
    links: faqLinksFor(category.title, item.q),
  })),
}));

export const allFaqs = faqCategories.flatMap((category) => category.items);

function compactAnswer(answer: string) {
  const clean = answer
    .replace(/```[\s\S]*?```/g, " ")
    .replace(/\|/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  const words = clean.split(" ");
  if (words.length <= 95) return clean;
  return `${words.slice(0, 86).join(" ")}...`;
}

function faqLinksFor(category: string, question: string): FaqLink[] {
  const text = `${category} ${question}`.toLowerCase();
  const links: FaqLink[] = [];

  if (text.includes("villa")) links.push({ label: "Villa cleaning", href: "/services/villa-cleaning" });
  if (text.includes("sofa") || text.includes("upholstery")) links.push({ label: "Sofa cleaning", href: "/services/sofa-cleaning" });
  if (text.includes("carpet")) links.push({ label: "Carpet cleaning", href: "/services/carpet-cleaning" });
  if (text.includes("office") || text.includes("commercial")) links.push({ label: "Office cleaning", href: "/services/office-cleaning" });
  if (text.includes("window")) links.push({ label: "Window cleaning", href: "/services/window-cleaning" });
  if (text.includes("pest")) links.push({ label: "Pest control", href: "/services/pest-control" });
  if (text.includes("move")) links.push({ label: "Move in/out cleaning", href: "/services/move-in-out-cleaning" });
  if (text.includes("deep") || category === "Deep Cleaning") links.push({ label: "Deep cleaning", href: "/services/deep-cleaning" });
  if (text.includes("price") || text.includes("cost") || text.includes("discount") || text.includes("bundle") || text.includes("package")) links.push({ label: "Pricing", href: "/pricing" });
  if (links.length === 0) links.push({ label: "All services", href: "/services" });
  if (!links.some((link) => link.href === "/contact")) links.push({ label: "Ask on WhatsApp", href: "/contact" });

  return dedupeLinks(links).slice(0, 3);
}

function dedupeLinks(links: FaqLink[]) {
  const seen = new Set<string>();
  return links.filter((link) => {
    if (seen.has(link.href)) return false;
    seen.add(link.href);
    return true;
  });
}
